qry:select.qry:xquery:
					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  POS27_CARPETAS.oi_carpeta as ID,
  POS27_CARPETAS.oi_carpeta as COD,
  POS27_CARPETAS.d_carpeta as DES
from
  POS27_CARPETAS
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

		for $r in SQL
('
	{%?($PARAM/@qryMode='LISTCAR')
	{%

	{%?($PARAM/@PYC!='1') {% fromrow {%=$PARAM/@fromrow%} maxsize {%=$PARAM/@maxsize%} %} {% maxsize 500 %} %}
	SELECT
	CAR.oi_carpeta,
	CAR.f_carpeta,
	CAR.d_carpeta,
	CAR.oi_usuario_sistema,
	CAR.d_creador,
	CAR.e_cant_cv
	%} {%%} %}

	{%?($PARAM/@qryMode='COUNTCAR')
	{% 
	  SELECT
	  COUNT(CAR.oi_carpeta) as cantTotal
	%} {%%} %}

	FROM
	POS27_CARPETAS as CAR    				

	WHERE 
	1=1
	{%? ($PARAM/@oi_usuario_sistema!='') {% AND CAR.oi_usuario_sistema = \'{%=$PARAM/@oi_usuario_sistema%}\'  %}{% %} %}
	{%? ($PARAM/@carpeta_like!='') {% AND contain(CAR.d_carpeta,{$PARAM/@carpeta_like})   %}{% %} %}

  {%?($PARAM/@qryMode='LISTCAR')
  {%			  
	  {%? ($PARAM/@activeOrder='TIT') {% ORDER BY d_carpeta {%=$PARAM/@order %}  %}{% %} %}
	  {%? ($PARAM/@activeOrder='FC') {% ORDER BY f_carpeta {%=$PARAM/@order %}  %}{% %} %}
	  {%? ($PARAM/@activeOrder='USR') {% ORDER BY d_creador {%=$PARAM/@order %}  %}{% %} %}
	  {%? ($PARAM/@activeOrder='CCV') {% ORDER BY e_cant_cv {%=$PARAM/@order %}  %}{% %} %}
  %} {%%} %}


	{%?($PARAM/@qryMode='COUNTCAR')
	{%

	%} {%%} %}			  

')/ROWS/ROW

					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  POS27_ASOCIA_CV_CAR.oi_car_cv as ID,
  POS27_ASOCIA_CV_CAR.oi_car_cv as COD,
  POS27_ASOCIA_CV_CAR.d_car_cv as DES,
  POS27_ASOCIA_CV_CAR.oi_carpeta as PARENT
from
  POS27_ASOCIA_CV_CAR
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

			for $r in SQL
	(' 				
	{%?($PARAM/@qryMode='LISTCAR')
	{%
		{%?($PARAM/@PYC='1') {%maxsize 500 %} {% fromrow {%=$PARAM/@fromrow%} maxsize {%=$PARAM/@maxsize%} %} %}

		SELECT
		CV.oi_cv,
		CV.d_ape_y_nom,								
	 	CV.d_localidad,
	 	CV.n_remuneracion,			 	 
	 	CV.edad,
	 	CV.oi_foto,
	 	CV.d_estado_civil,
	 	CV.d_email,
	 	CV.c_pais_cel,
		CV.c_area_cel,
		CV.te_celular,
		CV.c_pais,
		CV.c_area,
		CV.te_nro,
		CV.d_pais,
		CV.d_provincia,
		CV.d_calle,
		CV.c_nro,
		CV.c_piso,
		CV.c_departamento,
		CV.c_nro_doc,
		CV.c_sexo,
		CV.c_tipo_documento,
		CARCV.c_marca,
		CV.f_actualizacion,
		CV.c_cv,
		CV.c_estado	 
	%} {% %} %}				

	{%?($PARAM/@qryMode='COUNTALL')
	{%				
	 	SELECT
	 	CV.oi_cv

	%} {% %} %}	
	{%?($PARAM/@qryMode='RESUMEN')
	{%	
		 maxsize 5
		 SELECT
		  auxTabla.{%=$PARAM/@campoResumen%} as titulo,
			count(auxTabla.oi_cv) as cant  				 	 				 

		 FROM
		 ( 					 	
		 	SELECT
			CV.{%=$PARAM/@campoResumen%},CV.oi_cv
			FROM 
			POS27_ASOCIA_CV_CAR as CARCV,
			VW_BUSCAR_CV as CV 					     

			JOIN
			CARCV.oi_cv INNER CV.oi_cv
	%} 
	{% %} %}

	{%?($PARAM/@qryMode='PAGINATION')
	{%
		maxsize 501

		SELECT
			CV.oi_cv,
			CV.d_ape_y_nom,								
		 	CV.edad,
		 	CV.n_remuneracion
	%} 
	{% %} %}

	{%?($PARAM/@qryMode='LISTCAR' or $PARAM/@qryMode='COUNTALL' or $PARAM/@qryMode='PAGINATION')
	{% 	
		FROM     
		POS27_ASOCIA_CV_CAR as CARCV,
		VW_BUSCAR_CV as CV

		JOIN
		CARCV.oi_cv INNER CV.oi_cv

	 %} {% %} %}


	WHERE
	CARCV.oi_carpeta = {%=$PARAM/@oi_carpeta%}


	{%?($PARAM/@c_marca!=''){%AND CARCV.c_marca= \'{%=$PARAM/@c_marca%}\'  %} {% %} %}		

	{%? ($PARAM/@campo_buscar_1!='')  {% AND (contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_1%}\')%}{% %} %}
	{%? ($PARAM/@campo_buscar_2!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_2%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_3!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_3%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_4!='')  {% OR contain(CV.o_campo_like, \'{%=$PARAM/@campo_buscar_4%}\')%}{% %} %}
	{%? ($PARAM/@campo_buscar_5!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_5%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_6!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_6%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_7!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_7%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_8!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_8%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_9!='')  {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_9%}\') %}{% %} %}
	{%? ($PARAM/@campo_buscar_10!='') {% OR contain(CV.o_campo_like,\'{%=$PARAM/@campo_buscar_10%}\')%}{% %} %}

	{%? ($PARAM/@campo_buscar_1!='')  {%) %}{% %} %}		


	{%?($PARAM/@d_puesto!=''){%AND UCASE(CV.d_puesto) = UCASE(\'{%=$PARAM/@d_puesto%}\')  %} {% %} %}
	{%?($PARAM/@d_empresa!=''){%AND UCASE(CV.d_empresa) = UCASE(\'{%=$PARAM/@d_empresa%}\')  %} {% %} %}		
	{%?($PARAM/@d_estudio!=''){%AND UCASE(CV.d_estudio) = UCASE(\'{%=$PARAM/@d_estudio%}\')  %} {% %} %}		
	{%?($PARAM/@d_localidad!=''){%AND UCASE(CV.d_localidad) = UCASE(\'{%=$PARAM/@d_localidad%}\')  %} {% %} %}				


	{%?($PARAM/@qryMode='RESUMEN')
	{%	
	  AND isNotNull(CV.{%=$PARAM/@campoResumen%})  
	 %} {% %} %}	


	{%? ($PARAM/@l_leido='1')  {% AND CV.oi_usuario_sistema = \'{%=$PROXY/@ETTY%}\' %}{% %} %}
	{%? ($PARAM/@l_leido='0')  
		{% AND  
		    CARCV.oi_cv NOT IN (SELECT AUX.oi_cv FROM POS01_CV_LEIDO as AUX WHERE AUX.oi_usuario_sistema  = \'{%=$PROXY/@ETTY%}\')

		%}{% %} 
	%} 

	 {%? ($PARAM/@PYC='1')  
		 	{% 
		        AND CV.oi_cv NOT IN (SELECT PED01_DETALLE.oi_cv FROM PED01_DETALLE
									 WHERE PED01_DETALLE.oi_pedido = {%=$PARAM/@oi_pedido%})
		 	%} 
		 	{% 
		 	%}
		 %}	


	{%?($PARAM/@qryMode='LISTCAR')
	{%
		GROUP BY
		CV.oi_cv,CV.d_ape_y_nom,CV.d_localidad,CV.n_remuneracion,CV.edad,
 		CV.oi_foto,	CV.d_estado_civil,CV.d_email,CV.c_pais_cel,CV.c_area_cel,CV.te_celular,
		CV.c_pais,CV.c_area,CV.te_nro,CV.d_pais,CV.d_provincia,CV.d_calle,CV.c_nro,CV.c_piso,
		CV.c_departamento,CV.c_nro_doc,CV.c_sexo,CV.c_tipo_documento,CARCV.c_marca,CV.f_actualizacion,CV.c_cv,
		CV.c_estado	 										

		{%? ($PARAM/@activeOrder='AN') {% ORDER BY d_ape_y_nom {%=$PARAM/@order %}  %}{% %} %}
		{%? ($PARAM/@activeOrder='ED') {% ORDER BY edad {%=$PARAM/@order %}  %}{% %} %}
		{%? ($PARAM/@activeOrder='RE') {% ORDER BY n_remuneracion {%=$PARAM/@order %}  %}{% %} %}
	%}{% %} %}

	{%?($PARAM/@qryMode='RESUMEN')
		{% 
		 GROUP BY  CV.{%=$PARAM/@campoResumen%}, CV.oi_cv
		) as auxTabla				  

		  GROUP BY auxTabla.{%=$PARAM/@campoResumen%} 						 
		 	ORDER BY cant desc 			
		%} {%%} %}

	{%?($PARAM/@qryMode='COUNTALL')
		{% 	
		    	GROUP BY CV.oi_cv
		%} {%%} %}

	{%?($PARAM/@qryMode='PAGINATION')
	{%
	 	GROUP BY
			CV.oi_cv,
			CV.d_ape_y_nom,								
		 	CV.edad,
		 	CV.n_remuneracion	 										

		{%? ($PARAM/@activeOrder='AN') {% ORDER BY d_ape_y_nom {%=$PARAM/@order %}  %}{% %} %}
		{%? ($PARAM/@activeOrder='ED') {% ORDER BY edad {%=$PARAM/@order %}  %}{% %} %}
		{%? ($PARAM/@activeOrder='RE') {% ORDER BY n_remuneracion {%=$PARAM/@order %}  %}{% %} %}			
	%} {%%} %}

	')/ROWS/ROW
